const f = (frame, name) => {
  const fl = frame.fields.find(x => x.name === name);
  return fl ? (fl.values.toArray ? fl.values.toArray() : fl.values) : [];
};
const byRef = (id) => data.series.find(s => s.refId === id) || data.series.find(s => s.name === id);
const nodes = byRef('nodes') || data.series[0];
const edges = byRef('edges') || data.series[1];

const styles = {
  finalized: { color: '#2ECC71', size: 28, label: 'finalized' },
  justified: { color: '#3498DB', size: 24, label: 'justified' },
  invalid:   { color: '#E74C3C', size: 20, label: 'invalid' },
  normal:    { color: '#F39C12', size: 20, label: 'block' },
};
const HEAD_RING = '#FFD700';
const HEAD_RING_EXTRA = 12;
const OPT_BORDER = '#FBBF24';
const NORM_BORDER = '#1a1a1a';
const SLOTS_PER_EPOCH = 32;

const traces = {
  finalized: { x: [], y: [], text: [], hover: [], lineColors: [], lineWidths: [] },
  justified: { x: [], y: [], text: [], hover: [], lineColors: [], lineWidths: [] },
  invalid:   { x: [], y: [], text: [], hover: [], lineColors: [], lineWidths: [] },
  normal:    { x: [], y: [], text: [], hover: [], lineColors: [], lineWidths: [] },
};
const headRing = { x: [], y: [], size: [] };

const truthy = (v) => v === true || v === 'true' || v === 1 || v === '1';

let minSlot = Infinity, maxSlot = -Infinity;
if (nodes) {
  const slot = f(nodes, 'slot');
  const y    = f(nodes, 'y');
  const root = f(nodes, 'block_root');
  const wgt  = f(nodes, 'weight');
  const val  = f(nodes, 'validity');
  const kind = f(nodes, 'kind');
  const head = f(nodes, 'is_head');
  const opt  = f(nodes, 'is_optimistic');
  for (let i = 0; i < slot.length; i++) {
    const sn = Number(slot[i]); if (sn < minSlot) minSlot = sn; if (sn > maxSlot) maxSlot = sn;
    const k = traces[kind[i]] ? kind[i] : 'normal';
    const isOpt  = truthy(opt[i]);
    const isHead = truthy(head[i]);
    const slotInEpoch = Number(slot[i]) % SLOTS_PER_EPOCH;
    traces[k].x.push(slot[i]);
    traces[k].y.push(y[i]);
    traces[k].text.push(String(slotInEpoch));
    traces[k].lineColors.push(isOpt ? OPT_BORDER : NORM_BORDER);
    traces[k].lineWidths.push(isOpt ? 2.5 : 1);
    traces[k].hover.push(
      '<b>slot ' + slot[i] + '</b> (slot-in-epoch ' + slotInEpoch + ')'
      + (isHead ? ' <b style="color:' + HEAD_RING + '">[HEAD]</b>' : '')
      + '<br>' + (root[i] || '')
      + '<br>weight: ' + (wgt[i] || '')
      + '<br>validity: ' + (val[i] || '')
      + '<br>kind: ' + k
      + '<br>optimistic: ' + isOpt
    );
    if (isHead) {
      headRing.x.push(slot[i]);
      headRing.y.push(y[i]);
      headRing.size.push(styles[k].size + HEAD_RING_EXTRA);
    }
  }
}

const annotations = [];
if (edges) {
  const fs = f(edges, 'from_slot');
  const fy = f(edges, 'from_y');
  const ts = f(edges, 'to_slot');
  const ty = f(edges, 'to_y');
  for (let i = 0; i < fs.length; i++) {
    annotations.push({
      x: ts[i], y: ty[i],
      ax: fs[i], ay: fy[i],
      xref: 'x', yref: 'y', axref: 'x', ayref: 'y',
      showarrow: true,
      arrowhead: 3, arrowsize: 1.2, arrowwidth: 1.4,
      arrowcolor: 'rgba(200,200,200,0.55)',
      standoff: 14, startstandoff: 14,
    });
  }
}

const series = [];
if (headRing.x.length) {
  series.push({
    type: 'scatter', mode: 'markers',
    name: 'head', showlegend: true,
    x: headRing.x, y: headRing.y,
    hoverinfo: 'skip',
    marker: { symbol: 'square', color: 'rgba(0,0,0,0)', size: headRing.size, line: { color: HEAD_RING, width: 3 } },
  });
}
for (const k of Object.keys(styles)) {
  if (!traces[k].x.length) continue;
  series.push({
    type: 'scatter', mode: 'markers',
    name: styles[k].label, showlegend: true, legendgroup: k,
    x: [null], y: [null], hoverinfo: 'skip',
    marker: { symbol: 'square', color: styles[k].color, size: styles[k].size, line: { color: NORM_BORDER, width: 1 } },
  });
  series.push({
    type: 'scatter', mode: 'markers+text',
    name: styles[k].label, showlegend: false, legendgroup: k,
    x: traces[k].x, y: traces[k].y,
    text: traces[k].text,
    textposition: 'middle center',
    textfont: { color: '#0a0a0a', size: 10, family: 'monospace' },
    hovertext: traces[k].hover,
    hoverinfo: 'text',
    marker: {
      symbol: 'square',
      color: styles[k].color,
      size: styles[k].size,
      line: { color: traces[k].lineColors, width: traces[k].lineWidths },
    },
  });
}

return {
  data: series,
  layout: {
    xaxis: (() => {
      const ax = { showticklabels: true, zeroline: false, gridcolor: 'rgba(255,255,255,0.06)', title: { text: 'Epoch', font: { color: '#bbb' } } };
      if (isFinite(minSlot) && isFinite(maxSlot)) {
        const minEp = Math.floor(minSlot / SLOTS_PER_EPOCH);
        const maxEp = Math.floor(maxSlot / SLOTS_PER_EPOCH);
        const tickvals = [], ticktext = [];
        for (let e = minEp; e <= maxEp; e++) { tickvals.push(e * SLOTS_PER_EPOCH); ticktext.push(e.toLocaleString('en-US')); }
        ax.tickmode = 'array'; ax.tickvals = tickvals; ax.ticktext = ticktext;
      }
      return ax;
    })(),
    yaxis: { showticklabels: false, zeroline: false, gridcolor: 'rgba(255,255,255,0.05)' },
    annotations,
    showlegend: true,
    legend: { orientation: 'h', y: -0.08 },
    margin: { l: 20, r: 20, t: 10, b: 30 },
    plot_bgcolor: 'rgba(0,0,0,0)',
    paper_bgcolor: 'rgba(0,0,0,0)',
    font: { color: '#ddd' },
    hovermode: 'closest',
  },
  config: { displayModeBar: false }
};
